# ============================================
# ЭТАП 4: НОВЫЕ БЕТА-МОДУЛИ
# Автоматический скрипт развёртывания
# ============================================
$ErrorActionPreference = "Stop"
$root = "C:\ai-capitalS-mvp"

Write-Host "=== ЭТАП 4: Развёртывание новых модулей ===" -ForegroundColor Cyan

# Создать директории
New-Item -ItemType Directory -Force -Path "$root\app\services" | Out-Null
New-Item -ItemType Directory -Force -Path "$root\app\api\v1\routers" | Out-Null
New-Item -ItemType Directory -Force -Path "$root\app\templates\email" | Out-Null

# --- email_service.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\services\email_service.py", $bytes)
Write-Host "email_service.py -> OK" -ForegroundColor Green

# --- document_service.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\services\document_service.py", $bytes)
Write-Host "document_service.py -> OK" -ForegroundColor Green

# --- branded_pdf_service.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\services\branded_pdf_service.py", $bytes)
Write-Host "branded_pdf_service.py -> OK" -ForegroundColor Green

# --- email_digest.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\api\v1\routers\email_digest.py", $bytes)
Write-Host "email_digest.py -> OK" -ForegroundColor Green

# --- onboarding.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\api\v1\routers\onboarding.py", $bytes)
Write-Host "onboarding.py -> OK" -ForegroundColor Green

# --- documents.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\api\v1\routers\documents.py", $bytes)
Write-Host "documents.py -> OK" -ForegroundColor Green

# --- branded_export.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\api\v1\routers\branded_export.py", $bytes)
Write-Host "branded_export.py -> OK" -ForegroundColor Green

# --- admin_panel.py ---
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("$root\app\api\v1\routers\admin_panel.py", $bytes)
Write-Host "admin_panel.py -> OK" -ForegroundColor Green

# === Обновить Dockerfile ===
$df = Get-Content "$root\Dockerfile" -Raw
if ($df -notmatch "jinja2") {
    $old = "lxml"
    $new = "lxml`n    jinja2`n    reportlab`n    PyPDF2`n    python-docx`n    openpyxl`n    pdfplumber"
    $df = $df.Replace($old, $new)
    $df | Set-Content "$root\Dockerfile" -NoNewline
    Write-Host "Dockerfile обновлён (pip-пакеты добавлены)" -ForegroundColor Green
} else {
    Write-Host "Dockerfile уже содержит jinja2" -ForegroundColor Yellow
}

# === Обновить main.py ===
$main = Get-Content "$root\app\main.py" -Raw
if ($main -notmatch "email_digest") {
    $importLines = "`n# --- Stage 4: Beta modules ---`nfrom app.api.v1.routers import email_digest`nfrom app.api.v1.routers import onboarding`nfrom app.api.v1.routers import documents`nfrom app.api.v1.routers import branded_export`nfrom app.api.v1.routers import admin_panel"
    $routerLines = "`n# --- Stage 4: Beta modules ---`napp.include_router(email_digest.router, prefix=`"/api/v1`")`napp.include_router(onboarding.router, prefix=`"/api/v1`")`napp.include_router(documents.router, prefix=`"/api/v1`")`napp.include_router(branded_export.router, prefix=`"/api/v1`")`napp.include_router(admin_panel.router, prefix=`"/api/v1`")"

    # Найти последний include_router и вставить после него
    $lines = $main -split "`n"
    $lastImportIdx = -1
    $lastRouterIdx = -1
    for ($i = 0; $i -lt $lines.Count; $i++) {
        if ($lines[$i] -match "from app\.api\.v1\.routers import") { $lastImportIdx = $i }
        if ($lines[$i] -match "app\.include_router\(") { $lastRouterIdx = $i }
    }
    # Вставить роутеры
    if ($lastRouterIdx -ge 0) {
        $lines[$lastRouterIdx] = $lines[$lastRouterIdx] + $routerLines
    }
    # Вставить импорты
    if ($lastImportIdx -ge 0) {
        $lines[$lastImportIdx] = $lines[$lastImportIdx] + $importLines
    }
    ($lines -join "`n") | Set-Content "$root\app\main.py" -NoNewline
    Write-Host "main.py обновлён (5 роутеров добавлены)" -ForegroundColor Green
} else {
    Write-Host "main.py уже содержит email_digest" -ForegroundColor Yellow
}

# === Добавить SMTP в .env ===
$envContent = Get-Content "$root\.env" -Raw -ErrorAction SilentlyContinue
if ($envContent -notmatch "SMTP_HOST") {
    $smtp = "`n# --- Email (SMTP) ---`nSMTP_HOST=smtp.gmail.com`nSMTP_PORT=587`nSMTP_USER=`nSMTP_PASSWORD=`nSMTP_TLS=true"
    Add-Content "$root\.env" $smtp
    Write-Host ".env обновлён (SMTP добавлен)" -ForegroundColor Green
} else {
    Write-Host ".env уже содержит SMTP" -ForegroundColor Yellow
}

# === Пересобрать и запустить ===
Write-Host "`n=== Пересборка Docker... ===" -ForegroundColor Cyan
docker compose build --no-cache backend
docker compose up -d
Write-Host "`nОжидание запуска (15 сек)..." -ForegroundColor Yellow
Start-Sleep -Seconds 15
docker compose ps

# === Проверка ===
Write-Host "`n=== Проверка импортов Stage 4... ===" -ForegroundColor Cyan
docker exec ai_capital_backend python3 -c "from app.api.v1.routers import email_digest, onboarding, documents, branded_export, admin_panel; print('All Stage 4 modules imported OK')"

Write-Host "`n=== ЭТАП 4 ЗАВЕРШЁН ===" -ForegroundColor Green